"""
MKT Original Language Commentary — Genesis chapters 4–6
Run: python3 scripts/zc-original-genesis-4-6.py

Source data used:
- data/interlinear/genesis.json (verse inventory)
- data/translation/glossary-hebrew.json (key terms)
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/ellicott/genesis.json (philological notes)

Key decisions in this range:
- Ch 4 v7: ḥaṭṭāʾt personified as rābiṣ (crouching one) — Akkadian cognate
  connection retained; sin's "desire" (tĕšûqāh) parallels Gen 3:16 deliberately
- Ch 5 genealogy: each "and he died" (wayyāmōt) entry receives a note on the
  death-refrain as structural contrast to Enoch's translation
- Ch 6 v2: "sons of God" (bĕnê hāʾĕlōhîm) — three major interpretive positions
  noted; the text is philologically preserved without resolving the debate
- Ch 6 v6: divine "regret" (nāḥam) treated as anthropopathism, not divine
  ignorance; root connection to Noah's name preserved
- Ch 6 v14: gōper-wood and kōper-pitch noted — the pitch/atonement (kippûr)
  root connection is a recognized philological observation
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "4": {
    "1": """<p><strong>wayyēdaʿ ʾādām ʾet-ḥawwāh</strong>: "Adam knew Eve his wife." <em>Yādaʿ</em> (H3045) is the standard Hebrew verb for intimate covenantal knowing; it covers experiential, relational, and sexual knowledge in a single word that the English "knew" or the MKT's "made love" must unpack contextually. The name <em>Qayin</em> (Cain) is explained by Eve's wordplay: <em>qānîtî ʾîš ʾet-YHWH</em> — "I have acquired a man with/by YHWH." The verb <em>qānāh</em> (H7069) means to acquire, purchase, or create; Eve may be expressing gratitude for divine gift or, more boldly, a claim that she has participated in divine creation. The etymology is embedded in the name — the narrator preserves the theological self-understanding of the character in the very word that names him.</p>""",
    "2": """<p><strong>hābel rōʿēh ṣōʾn wĕqayin hāyāh ʿōbēd ʾădāmāh</strong>: Abel is a keeper of flocks; Cain is a tiller of the ground. The name <em>Hābel</em> (Abel, H1893) means breath, vapor, or vanity — the same word that opens Ecclesiastes ("Vanity of vanities, all is <em>hābel</em>"). Whether this reflects retrospective naming or anticipates his early death is disputed, but the text allows the association. The two vocations divide the brothers by their relation to the ground: Cain works the cursed earth of Gen 3:17; Abel tends animals that graze above it.</p>""",
    "3": """<p><strong>miqṣēh yāmîm ... minḥāh laYHWH</strong>: "In the course of time Cain brought from the fruit of the ground an offering to YHWH." <em>Minḥāh</em> (H4503) is the standard word for a tribute or grain offering — used in Levitical law for non-animal offerings but also generically for any gift presented to a superior. The phrase does not specify what was wrong with Cain's offering at this stage; the text delays explanation until v4-5. <em>Miqṣēh yāmîm</em> (literally "from the end of days") indicates a recurring or periodic occasion, not a one-time event.</p>""",
    "4": """<p><strong>wĕhābel hēbîʾ gam-hûʾ mibĕkōrôt ṣōʾnô ûmēḥelbêhen</strong>: "Abel also brought from the firstborn of his flock and from their fat portions." Two qualifiers distinguish Abel's offering: (1) <em>bĕkōrôt</em> (firstborn/firstlings) — the first and therefore best of the flock, with covenantal priority (cf. Exod 13:2; Deut 15:19-20); (2) <em>ḥelĕbêhen</em> (fat portions) — the choicest, most valued part, reserved for God in later Levitical law (Lev 3:16). The text makes no complaint about Cain's species of offering; the contrast is quality and priority of what each brought. <em>Wayyišaʿ</em> (looked with favor) — <em>šāʿāh</em> (H8159) means to gaze intently at or regard approvingly, implying a divine assessment, not merely emotional preference.</p>""",
    "5": """<p><strong>wĕʾel-qayin wĕʾel-minḥātô lōʾ šāʿāh</strong>: "But to Cain and his offering he did not look with favor." The Hebrew construction pairs the person and the offering under a single verb, suggesting a unity: it is Cain-and-his-offering as a composite that is refused. <em>Wayyiḥar lĕqayin mĕʾōd</em> (Cain was very angry) — <em>ḥārāh</em> (H2734) is a term for burning anger; <em>mĕʾōd</em> (exceedingly) intensifies it. <em>Wayyippĕlû pānāyw</em> (his face fell/was downcast) — the face as the site of honor and shame; a fallen face signals both grief and indignation. The outward sign precedes the inner murderous intent that God immediately addresses.</p>""",
    "6": """<p><strong>wayyōʾmer YHWH ʾel-qayin lāmmāh ḥārāh lāk wĕlāmmāh nāpĕlû pānêkā</strong>: "Why are you angry, and why has your face fallen?" The divine interrogation uses the same terms from v5: <em>ḥārāh</em> (burning anger) and <em>nāpĕlû pānêkā</em> (fallen face). God's question is not ignorant inquiry — the Hebrew interrogative <em>lāmmāh</em> (why?) functions as a challenge that calls for self-examination, not mere information. The pattern is identical to 3:9 ("Where are you?"): God asks not because he lacks the answer but because he gives the human space to answer honestly before pronouncing judgment.</p>""",
    "7": """<p><strong>ḥaṭṭāʾt rōbēṣ</strong>: "Sin is crouching." <em>Ḥaṭṭāʾt</em> (H2403) is the standard word for sin and also for the sin-offering that makes atonement for it — the word carries both the offense and its remedy in a single term. Here it is personified as <em>rōbēṣ</em> (H7257, crouching/lurking) — the participial form of a verb that describes an animal crouched in wait. The Akkadian cognate <em>rābiṣu</em> denotes a guardian demon that lurks at doorways; the Mesopotamian background gives the image supernatural menace without requiring a direct demon reference.</p><p><em>Wĕʾēlêkā tĕšûqātô wĕʾattāh timšol-bô</em>: "Its desire is for you, but you must rule over it." <em>Tĕšûqāh</em> (H8669, desire/longing) is the same word used of the woman's desire for her husband in 3:16, creating a deliberate echo: the disordered desire that entered human relationships in ch. 3 now appears as the character of sin itself. <em>Māšal</em> (H4910, rule/have dominion) repeats the language of 1:26-28; Cain is told he can do what Adam failed to do — but only if he acts rightly.</p>""",
    "8": """<p><strong>wayyāqom qayin ʾel-hābel ʾāḥîw wayyahargēhû</strong>: "Cain rose against his brother Abel and killed him." The Hebrew is stark and unadorned — no internal monologue, no plan, no narrative delay. <em>Wayyāqom</em> (rose up/arose) is a verb of sudden violent action; <em>hārag</em> (H2026, killed) is unambiguous — it is murder, not manslaughter. The narrator frames the act by repeating <em>ʾāḥîw</em> (his brother) at the end: "he killed him — his brother." The repeated kinship term underscores the covenant violation: the first murder is also the first fratricide.</p>""",
    "9": """<p><strong>ʾî hābel ʾāḥîkā</strong>: "Where is Abel your brother?" Again the divine question with implied omniscience — God already knows. Cain's answer <em>lōʾ yādaʿtî</em> (I do not know) uses the same verb <em>yādaʿ</em> from v1 — the "knowing" that opens this chapter (Adam knew Eve; God knows where Abel is) is now refused by Cain. <em>Hăšōmēr ʾāḥî ʾānōkî</em>: "Am I my brother's keeper?" The word <em>šōmēr</em> (keeper/guardian) is used in Num 3:38 for those who guard the tabernacle — ironically, Cain is precisely his brother's designated guardian in the covenantal sibling order he has violated.</p>""",
    "10": """<p><strong>qôl dĕmê ʾāḥîkā ṣōʿăqîm ʾēlay min-hāʾădāmāh</strong>: "The voice of your brother's blood is crying out to me from the ground." <em>Dāmîm</em> (bloods) is plural — the plural of blood often denotes bloodguilt or shed blood specifically. <em>Ṣāʿaq</em> (H6817, to cry out/appeal) is a judicial term — it denotes the cry of a victim appealing to a judge or avenger (cf. Exod 22:23; Deut 22:27). The ground itself becomes a witness and complainant; the inanimate creation testifies against the murderer. The language anticipates the concept of the "avenger of blood" (<em>gōʾēl haddām</em>) that becomes formalized in Num 35.</p>""",
    "11": """<p><strong>ʾārûr ʾattāh min-hāʾădāmāh</strong>: "Cursed are you from the ground, which has opened its mouth to receive your brother's blood from your hand." Cain is cursed <em>min-hāʾădāmāh</em> (from/by the ground) — not just expelled from it, but alienated from the very element that was his livelihood. The ground is personified as having "opened its mouth" to receive the blood, making it both victim and witness. The curse escalates from Gen 3:17: there the ground was cursed <em>for Adam's sake</em>; here Cain is cursed <em>from the ground</em> — a more direct and personal alienation.</p>""",
    "12": """<p><strong>nāʿ wānād tihyeh bāʾāreṣ</strong>: "A restless wanderer you will be on the earth." <em>Nāʿ wānād</em> is a word-pair — <em>nûaʿ</em> (H5128, to shake/stagger/wander) + <em>nûd</em> (H5110, to nod/wander/show sympathy) — combining two words for aimless motion. The phrase occurs only here and in v14; it is the deliberate reversal of Cain's identity as a tiller of the ground (<em>ʿōbēd ʾădāmāh</em>, v2). The one who cultivated the earth is now excluded from cultivating it; the agricultural man becomes the homeless wanderer.</p>""",
    "13": """<p><strong>gādôl ʿăwōnî miṇṇĕśōʾ</strong>: "My punishment is greater than I can bear" — or, "My iniquity is too great to be forgiven." <em>ʿĀwōn</em> (H5771) is ambiguous: it means both the sinful act and the punishment/consequence it brings. <em>Miṇṇĕśōʾ</em> (from being carried/lifted) can mean "too great to carry" (unbearable punishment) or "too great to be lifted off" (unforgivable guilt). The translation "bear" collapses both; the Hebrew preserves the ambiguity intentionally. Cain's complaint is simultaneously a recognition of guilt and a cry of self-pity — he describes the consequences accurately but shows no repentance.</p>""",
    "14": """<p><strong>ûmippānêkā ʾessātēr</strong>: "And from your face I will be hidden." <em>Pānîm</em> (face) — the divine countenance is the source of covenant blessing (Num 6:25-26; Ps 31:16). To be hidden from God's face is to lose covenant standing — this is the worst of the consequences Cain lists. The phrase connects to Gen 3:8 ("they hid themselves from the face of YHWH God") but there the hiding was the humans' action; here it is the structural consequence of the curse. The "land of Nod" (<em>ʾereṣ nôd</em>, v16) is named from the same root as <em>nûd</em> (wandering) — it is literally "the land of wandering."</p>""",
    "15": """<p><strong>lākēn kol-hōrēg qayin šibʿātayim yuqqām</strong>: "Therefore, anyone who kills Cain will suffer vengeance sevenfold." <em>Šibʿātayim</em> (sevenfold) — the number seven in biblical idiom connotes completeness; sevenfold vengeance is total divine protection. The <em>ʾôt</em> (H226, mark/sign) placed on Cain is the same word used for covenantal signs: rainbow (Gen 9:12), circumcision (Gen 17:11), blood on doorposts (Exod 12:13). The mark is not a brand of shame but a protective sign; its nature is not described. YHWH's protection of the murderer demonstrates the principle of common grace: God preserves fallen humanity to prevent self-annihilation before the purposes of redemption are accomplished.</p>""",
    "16": """<p><strong>wayyēṣēʾ qayin millipnê YHWH wayyēšeb bĕʾereṣ-nôd qidmat-ʿēden</strong>: "Cain went out from the presence of YHWH and settled in the land of Nod, east of Eden." <em>Qidmat-ʿēden</em> (east of Eden) echoes the expulsion direction of 3:24 (the cherubim are placed east of the garden). East in Genesis is the direction of exile and departure from the divine presence (cf. also Lot's departure toward Sodom, 13:11-12). The land of Nod is not a geographical region on any ancient map; its name (<em>nûd</em>, wandering) identifies it as the territory of homelessness itself — a theological rather than cartographic location.</p>""",
    "17": """<p><strong>wayyiben qayin ʿîr</strong>: "Cain built a city." The irony is pointed: the restless wanderer under a curse of displacement immediately founds a city — a permanent human settlement. <em>ʿÎr</em> (H5892, city/town) is the first city in Scripture, built by the first murderer. The name <em>ḥănôk</em> (Enoch) means "dedication" or "initiation" — Cain dedicates the first built environment to his son's name, not to YHWH's. This contrasts with the later calling on YHWH's name in v26.</p>""",
    "18": """<p><strong>wayyiwwālēd lĕḥănôk ʾet-ʿîrād</strong>: "To Enoch was born Irad." The Cainite genealogy (vv17-24) runs seven generations from Adam (Adam → Cain → Enoch → Irad → Mehujael → Methushael → Lamech). The names in the Cainite line have parallels in the Sethite line of ch. 5 (Enoch/Enoch, Lamech/Lamech, Methushael/Methuselah), suggesting either shared naming traditions, deliberate contrasts, or an ancient compiler's parallel arrangement of two traditions. The structural parallelism does not indicate that the lines are identical — the narrator distinguishes them clearly by lineage and outcome.</p>""",
    "19": """<p><strong>wayyiqqaḥ lô lemek šĕtê nāšîm</strong>: "Lamech took two wives." This is the first occurrence of polygamy in Scripture. The narrator introduces it without explicit commentary, but its place in the Cainite genealogy — the line marked by murder, wandering, and divine estrangement — gives it a negative context. The verb <em>lāqaḥ</em> (H3947, to take/acquire) is the standard verb for taking a wife in the patriarchal narrative; the specification of two signals a departure from the one-flesh pattern of Gen 2:24.</p>""",
    "20": """<p><strong>ʾābî yōšēb ʾōhel ûmiqneh</strong>: "The father of those who dwell in tents and keep livestock." Jabal is identified as the progenitor of pastoral nomadism — the same livelihood as Abel. The Cainite line, marked by the murder of the shepherd, ironically generates the shepherd-culture. <em>ʾĀbî</em> (father of) functions as "founder of" or "originator of" a cultural tradition; this is a genealogical formula for the origin of human cultural specializations.</p>""",
    "21": """<p><strong>ʾābî kol-tōpēś kinnôr wĕʿûgāb</strong>: "The father of all who play the lyre and pipe." Musical instruments are attributed to the Cainite line — <em>kinnôr</em> (lyre/harp, later David's instrument; H3658) and <em>ʿûgāb</em> (pipe/flute; H5748). The attribution of music, livestock, and metalworking to Cain's descendants reflects an ANE tradition of tracing cultural achievements to legendary ancestors. In context it is morally neutral description rather than condemnation; human civilization — art, agriculture, technology — develops from the fallen line.</p>""",
    "22": """<p><strong>tûbal-qayin lōṭēš kol-ḥōrēš nĕḥōšet ûbarzel</strong>: "Tubal-Cain, the forger of all instruments of bronze and iron." <em>Lōṭēš</em> (H3913, sharpen/forge) is a technical smithing term. Bronze (<em>nĕḥōšet</em>) and iron (<em>barzel</em>) represent the metals of weapon-making in ANE contexts; the Cainite line produces pastoral culture (Jabal), musical culture (Jubal), and weapons technology (Tubal-Cain) — a complete civilization arising from the cursed line.</p>""",
    "23": """<p><strong>šimʿan qôlî nĕšê lemek</strong>: The Song of the Sword (vv23-24) is among the oldest poetic fragments in Genesis, recognizable by its parallel stichoi and archaic style. Lamech's boast escalates Cain's protection sevenfold to Lamech's self-proclaimed seventy-sevenfold vengeance. <em>Hāragtî ʾîš lĕpitʿî</em>: "I have killed a man for wounding me" — the verb <em>hārag</em> (killed) is the same used of Cain's murder in v8; Lamech celebrates rather than laments. The poem shows the degenerative spiral: sin's entry (ch. 3) → fratricidal murder (v8) → institutionalized revenge culture (vv23-24).</p>""",
    "24": """<p><strong>kî šibʿātayim yuqqam qayin wĕlemek šibʿîm wĕšibʿāh</strong>: "If Cain is avenged sevenfold, then Lamech seventy-sevenfold." The escalation from seven to seventy-seven is arithmetically exact (seven multiplied to the second level of completeness). Jesus reverses this exact calculus in Matt 18:22: "Not seven times, but seventy-seven times" — forgiveness is to escalate by the same magnitude that revenge did. The NT is reading the Lamech poem when it sets the counter-principle of unlimited forgiveness against unlimited retaliation.</p>""",
    "25": """<p><strong>wayyāšet lî ʾĕlōhîm zeraʿ ʾaḥēr taḥat hābel</strong>: "God has appointed for me another offspring in place of Abel." The name <em>Šēt</em> (Seth, H8352) is explained by Eve as deriving from <em>šāt</em> (H7896, to appoint/set) — God has set/appointed a replacement. This is a theological naming that sees Seth not as a genetic replacement but as a covenantal appointment — the line through which the seed-promise of 3:15 will continue. The verb <em>šātat</em> (appointed) contrasts with the name Cain (acquired/purchased): Seth is gift, not achievement.</p>""",
    "26": """<p><strong>ʾāz hūḥal liqrōʾ bĕšēm YHWH</strong>: "Then people began to call on the name of YHWH." <em>Hūḥal</em> (from <em>ḥālal</em>, H2490) is rendered variously as "began" or "was profaned" depending on whether it is read as Hophal of <em>yāḥal</em> (began) or Hophal of <em>ḥālal</em> (to profane). If the latter, the verse is ironic — worship of YHWH's name began, but it was already being profaned by the Cainite culture. The majority reading is "began" (worship started with the birth of Enosh). <em>Šēm YHWH</em> (the name of YHWH) — invoking the divine name is a liturgical act; this is the first explicit reference to communal worship in Scripture, located not at a shrine but in the context of Enosh's birth, whose name (<em>ʾĕnôš</em>, H583) means "mortal/weak human."</p>"""
  },
  "5": {
    "1": """<p><strong>sēper tôlĕdōt ʾādām</strong>: "This is the scroll/document of the generations of Adam." <em>Sēper</em> (H5612, scroll, document, book) is the first use of the word "book" in the Bible — this genealogy is presented as a written record, not merely an oral tradition. <em>Tôlĕdōt</em> (H8435, generations/account) is the structural marker of Genesis (2:4; 5:1; 6:9; etc.); it introduces each major section. The verse then recapitulates 1:26-27: God created humanity (<em>ʾādām</em>) in the likeness (<em>dĕmût</em>, H1823) of God. The repetition anchors the genealogy in the creation mandate — these are the offspring of the image-bearers.</p>""",
    "2": """<p><strong>zākār ûnĕqēbāh bĕrāʾām waybārek ʾōtām</strong>: "Male and female he created them, and he blessed them." The creation binary (<em>zākār ûnĕqēbāh</em>) and the blessing are restated from 1:27-28 at the head of the post-fall genealogy, signaling that the image and blessing remain despite the expulsion. <em>Wayyiqrāʾ ʾet-šĕmām ʾādām</em>: "And he named them 'Mankind'" — God names the human pair collectively with the generic noun, tying individual identity to species-identity in a way that makes Adam's fall genuinely corporate.</p>""",
    "3": """<p><strong>bĕdamûtô kĕṣalmô</strong>: "In his own likeness, after his own image." The reversal from v1-2 is subtle but deliberate: creation says God made Adam in God's image and likeness; here Adam begets Seth in Adam's image and likeness. The same vocabulary (<em>ṣelem</em> + <em>dĕmût</em>) is used in both directions. The implication is that the image transmitted through human generation is now the image of fallen Adam, not the pristine image of 1:26 — though not destroyed, it is now refracted through a fallen bearer. This is the philological basis for the Reformed doctrine of original sin's transmission through natural generation.</p>""",
    "4": """<p><strong>wayyihyû yĕmê-ʾādām ʾaḥărê hôlîdô ʾet-šēt šĕmōneh mēʾôt šānāh</strong>: "The days of Adam after he fathered Seth were 800 years." The formulaic structure of ch. 5 — birth age of key son, remaining years, total, "and he died" — is the basic unit of the genealogy. The function of <em>wayyāmōt</em> (and he died) is not merely chronological; it is the structural response to 2:17 ("you will surely die"). Each entry in the genealogy is a case study in the execution of the death sentence announced in the garden. Adam lives 930 years — long, but finite.</p>""",
    "5": """<p><strong>wayyāmōt</strong>: "And he died." The three-word refrain at the end of each genealogical entry (<em>wayyihyû kol-yĕmê [name] ... šānāh wayyāmōt</em>) functions as a liturgical reminder: the death sentence of 2:17 is inescapable. Adam, despite living 930 years, dies. The absence of this refrain for Enoch (v24: "and he was no more, for God took him") is structurally arresting — the exception that proves the rule and points forward to bodily resurrection as the ultimate exception.</p>""",
    "6": """<p><strong>wayyĕḥî šēt ḥămiš šānîm ûmĕʾat šānāh wayyôled ʾet-ʾĕnôš</strong>: "When Seth had lived 105 years, he fathered Enosh." <em>ʾĔnôš</em> (H583) derives from a root meaning weak, sick, or mortal — the same root that gives us the common noun for "mortal man" in Hebrew poetry (e.g., Ps 8:4; 90:3). The name of the second generation after Adam means mortality itself — the genealogy is not optimistic about the trajectory of post-fall humanity.</p>""",
    "7": """<p><strong>wayyĕḥî-šēt ʾaḥărê hôlîdô ʾet-ʾĕnôš šebāʿ šānîm ûšĕmōneh mēʾôt šānāh</strong>: The formulaic structure continues. The long lifespans of the antediluvian genealogy have prompted several explanations: (1) genuine pre-flood longevity reflecting a different pre-flood environment; (2) compressed generational counts (years = short periods); (3) scribal transmission of an ancient kinglist tradition. Whatever their historical referent, within the narrative they convey an era of extended human vitality before the flood — the pre-curse creation still bearing fruit in bodily longevity even as it decays morally.</p>""",
    "8": """<p><strong>wayyāmōt</strong>: "And he died." Seth's 912 years end with the same refrain. The death formula is not varied or softened — each entry ends identically. The structural effect is cumulative: nine consecutive "and he died" entries (except Enoch) builds an inexorable rhetorical weight. Death is the universal conclusion to human biography in this chapter, broken only once.</p>""",
    "9": """<p><strong>wayyĕḥî ʾĕnôš tišʿîm šānāh wayyôled ʾet-qênān</strong>: "When Enosh had lived 90 years, he fathered Kenan." The name <em>qênān</em> (Kenan, H7018) may relate to the root <em>qwn</em> (to lament/wail) or to <em>qānāh</em> (acquire) — its derivation is uncertain. The Sethite genealogy proceeds without the cultural achievements attributed to the Cainite line (vv17-22): no cities, no music, no metallurgy — only births, years, and deaths. The Sethite line is characterized not by cultural accomplishment but by the continuity of the covenant seed.</p>""",
    "10": """<p><strong>wayyĕḥî ʾĕnôš ʾaḥărê hôlîdô ʾet-qênān</strong>: The formula continues. The pattern of lifespans in ch. 5 is not random: most run between 777 and 969 years, with Enoch's 365 being notably shorter (and complete in a solar-year sense). The longevity is presented as the norm; the post-flood genealogy of ch. 11 shows a systematic decrease toward the normal human lifespan, documenting the progressive enactment of the creation's groaning under the fall.</p>""",
    "11": """<p><strong>wayyāmōt</strong>: "And he died." Enosh dies after 905 years. The refrain accumulates. The reader of the Hebrew feels the grammatical finality of <em>wayyāmōt</em> — the waw-consecutive perfect (narrative past) form that terminates each biography. Death is not presented as natural or fitting; it is the sentence carried out. The genealogy is not celebrating longevity — it is documenting the execution of 2:17 across generations.</p>""",
    "12": """<p><strong>wayyĕḥî qênān šibʿîm šānāh wayyôled ʾet-mahălalʾēl</strong>: "When Kenan had lived 70 years, he fathered Mahalalel." <em>Mahălalʾēl</em> (H4111) means "praise of God" — the first clearly theophoric name in the Sethite genealogy. The pattern of names in ch. 5 has been interpreted cumulatively as an encoded theological message (Adam = man; Seth = appointed; Enosh = mortal; Kenan = sorrow; Mahalalel = blessed God; Jared = shall come down; Enoch = teaching; Methuselah = his death shall bring; Lamech = powerful; Noah = comfort) — though speculative and disputed, the theophoric naming pattern is real.</p>""",
    "13": """<p><strong>wayyĕḥî qênān ʾaḥărê hôlîdô ʾet-mahălalʾēl</strong>: Kenan lives 840 additional years after fathering Mahalalel. The mathematical precision of the genealogy — exact ages at fathering, exact additional years, exact totals — reflects either historical record-keeping or a literary convention of precision to convey authenticity. The Mesopotamian king-lists use similar formulaic precision for antediluvian rulers with even longer reigns (Alulim of Eridu reigns 28,800 years in one tradition), suggesting a shared ANE convention for the deep past.</p>""",
    "14": """<p><strong>wayyāmōt</strong>: "And he died." Kenan's 910 years conclude with the refrain. The fourth death in the genealogy. The cumulative effect of the death refrain in ch. 5 is to create what one commentator called a "monotonous minor key" — every biography, however long, ends on the same note. The genealogy is not triumphalist; it is brutally honest about the human condition under the sentence of 2:17.</p>""",
    "15": """<p><strong>wayyĕḥî mahălalʾēl ḥāmēš šānîm wĕšiššîm šānāh wayyôled ʾet-yāred</strong>: "When Mahalalel had lived 65 years, he fathered Jared." <em>Yāred</em> (H3382, Jared) may derive from <em>yārad</em> (to descend/come down). The structural placement of Jared as the father of Enoch (v18) — the man who walks with God and is taken by God — is significant: Jared parents the great exception to the death formula.</p>""",
    "16": """<p><strong>wayyĕḥî mahălalʾēl ʾaḥărê hôlîdô ʾet-yāred</strong>: The formula continues with Mahalalel living 830 additional years. The precision of the age-at-fathering figures enables chronologists to calculate the date of the flood from the creation (the "Anno Mundi" tradition of Ussher and others derives from exactly this arithmetic in chs. 5 and 11). The genealogy functions as a chronological spine, not merely a name-list.</p>""",
    "17": """<p><strong>wayyāmōt</strong>: "And he died." Mahalalel's 895 years end with the refrain. The fifth death. The genealogy has now carried the death formula through five entries; by the time the reader reaches Enoch in v24, the structural interruption of the refrain is felt sharply. Each successive death makes the exception more striking.</p>""",
    "18": """<p><strong>wayyĕḥî-yāred šĕtayim wĕšiššîm šānāh ûmĕʾat šānāh wayyôled ʾet-ḥănôk</strong>: "When Jared had lived 162 years, he fathered Enoch." <em>Ḥănôk</em> (Enoch, H2585) means "dedicated" or "initiated" — the same name as Cain's son in 4:17, but in the Sethite line a different person. The parallel names in the Cainite and Sethite genealogies (Enoch, Lamech) have been explained as either parallel cultural traditions, deliberate literary contrast, or a compiler's acknowledgment of shared naming stock.</p>""",
    "19": """<p><strong>wayyĕḥî-yāred ʾaḥărê hôlîdô ʾet-ḥănôk šĕmōneh mēʾôt šānāh</strong>: The formula continues with Jared's remaining 800 years. Jared lives 962 years total — the second longest lifespan after Methuselah (969, v27) — and then dies with the formula. His son Enoch will break the pattern. The contrast is prepared gradually: the longest-lived fathers the shortest-lived (in years on earth).</p>""",
    "20": """<p><strong>wayyāmōt</strong>: "And he died." Jared's 962 years end. Six deaths recorded. The structural preparation for Enoch is now nearly complete — six entries with the death refrain, setting the stage for the seventh to be different. The number seven carries covenantal weight in Genesis (seven days of creation; Lamech's sevenfold vengeance); the seventh entry in the death sequence breaks the pattern.</p>""",
    "21": """<p><strong>wayyĕḥî ḥănôk ḥāmēš wĕšiššîm šānāh wayyôled ʾet-mĕtûšālaḥ</strong>: "When Enoch had lived 65 years, he fathered Methuselah." <em>Mĕtûšālaḥ</em> (Methuselah, H4968) is explained in various traditions as "man of the javelin" (<em>mat</em> + <em>šelaḥ</em>) or as "his death shall bring" (<em>mût</em> + <em>šālaḥ</em>). The second etymology, if correct, would make Methuselah's death the appointed signal for the flood — and the chronology of Gen 5 and 7 shows Methuselah dying in the year of the flood. Whether intended by the narrator is debated, but the name has been read as a divine calendar embedded in the genealogy.</p>""",
    "22": """<p><strong>wayyithallēk ḥănôk ʾet-hāʾĕlōhîm</strong>: "Enoch walked with God." The verb is <em>hithallēk</em> — the Hithpael (reflexive/intensive) stem of <em>hālak</em> (H1980, to walk). The Hithpael of <em>hālak</em> denotes a reciprocal, ongoing, habitual walking — not a single journey but a continuous mode of life. It is the same form used of Noah in 6:9 and of the expected behavior of covenant partners (Lev 26:12: "I will walk among you"). The phrase is not "walked before God" (as Abraham walks, 17:1) or "walked in the ways of God" but "walked with God" — language of intimate companionship, the closest OT description of the pre-fall state available to a post-fall person.</p>""",
    "23": """<p><strong>wayyihyû kol-yĕmê ḥănôk ḥāmēš wĕšiššîm šānāh ûšĕlōš mēʾôt šānāh</strong>: "All the days of Enoch were 365 years." Enoch's total lifespan (365 years) is the shortest in the pre-flood genealogy and equals the number of days in a solar year. Whether this is coincidence or deliberate symbolism is debated. What is clear is that 365 is dramatically less than his peers (Seth 912, Enosh 905, Methuselah 969); his earthly time is abbreviated not by death but by translation.</p>""",
    "24": """<p><strong>wayyithallēk ḥănôk ʾet-hāʾĕlōhîm wĕʾênennû kî-lāqaḥ ʾōtô ʾĕlōhîm</strong>: "Enoch walked with God, and he was no more, for God took him." The death refrain breaks: instead of <em>wayyāmōt</em> (and he died), the text says <em>wĕʾênennû</em> (and he was not/no more) — the same construction used in 37:30 (Joseph is "no more") and Jer 31:15 (the children "are no more"). The verb <em>lāqaḥ</em> (H3947, to take) is the same verb used of Elijah's translation in 2 Kgs 2:3,5,9,10 ("the LORD will take your master from over you"). The LXX translates <em>wayyithallēk ḥănôk ʾet-hāʾĕlōhîm</em> as "Enoch pleased God," which Heb 11:5 quotes directly ("By faith Enoch was taken up so that he should not see death"). The Hebrew says "walked with"; the LXX says "pleased" — both are legitimate interpretations of the idiom, and the NT uses the LXX reading to make the faith connection explicit.</p>""",
    "25": """<p><strong>wayyĕḥî mĕtûšālaḥ šebāʿ wĕšĕmōnîm šānāh ûmĕʾat šānāh wayyôled ʾet-lāmek</strong>: "When Methuselah had lived 187 years, he fathered Lamech." The formula resumes after Enoch's exceptional entry. Methuselah returns the genealogy to normalcy — his son Lamech will be Noah's father, and Methuselah will die in the year of the flood (if the etymology of his name is accepted). The genealogy is now building toward its climax in Noah.</p>""",
    "26": """<p><strong>wayyĕḥî mĕtûšālaḥ ʾaḥărê hôlîdô ʾet-lāmek</strong>: The formula continues with Methuselah's remaining 782 years, giving him a total of 969 (v27) — the longest lifespan in the genealogy. The narrator may intend irony: the man whose name may mean "his death shall bring [the flood]" lives longest. His endurance is a species of divine patience, giving humanity maximum time before judgment arrives.</p>""",
    "27": """<p><strong>wayyāmōt</strong>: "And he died." Methuselah's 969 years conclude with the refrain. This is the penultimate death formula; after Lamech's death (v31), the genealogy will conclude with Noah's birth — not his death. The oldest man in recorded Scripture dies with the same three-word sentence as every other. Age does not exempt from the sentence of 2:17; only translation (Enoch) and the covenant (Noah) offer alternatives.</p>""",
    "28": """<p><strong>wayyĕḥî-lāmek šĕtayim wĕšĕmōnîm šānāh ûmĕʾat šānāh wayyôled bēn</strong>: "When Lamech had lived 182 years, he had a son." The departure from the formula here is subtle: the text says "he had a son" (<em>ben</em>) rather than naming the son immediately, delaying the name for the interpretive comment in v29. The name-comment structure signals a significant naming — not merely a genealogical entry but a prophetic declaration.</p>""",
    "29": """<p><strong>wayyiqrāʾ ʾet-šĕmô nōaḥ lēmōr zeh yĕnaḥămēnnû</strong>: "He named him Noah, saying, 'This one will comfort us.'" <em>Nōaḥ</em> (H5146) and <em>yĕnaḥămēnnû</em> (he will comfort us) connect to the root <em>nāḥam</em> (H5162, to comfort/relent/sigh) — the same root used of God's regret in 6:6. Noah's name is the linguistic bridge between the Lamech prophecy and the divine response to wickedness. Lamech's prophecy anticipates rest from the curse of the ground (citing 3:17); Noah will bring this rest through the flood — not by removing the curse, but by preserving the covenant seed through judgment and into a new post-flood order (8:21-22).</p>""",
    "30": """<p><strong>wayyĕḥî lāmek ʾaḥărê hôlîdô ʾet-nōaḥ</strong>: Lamech lives 595 additional years after Noah's birth — a post-fathering life somewhat shorter than his peers (Methuselah lives 782 additional years; Jared 800). The compressed trajectory may be incidental or may reflect the narrowing pre-flood period as judgment approaches. Lamech dies before the flood (5:31 gives his total as 777 years; the flood comes in Noah's 600th year, Gen 7:6).</p>""",
    "31": """<p><strong>wayyāmōt</strong>: "And he died." Lamech's 777 years conclude the second-to-last individual biography in the genealogy. The number 777 carries obvious triple-seven symbolism in a book where seven is covenantally significant (7 days of creation, 7-fold vengeance, 70x7 forgiveness). Whether the narrator intends the numerical symbolism or is recording a genuine traditional lifespan is a question the text does not resolve, but the triple pattern is structurally present.</p>""",
    "32": """<p><strong>wayyôled nōaḥ ʾet-šēm ʾet-ḥām wĕʾet-yāpet</strong>: "And Noah fathered Shem, Ham, and Japheth." The genealogy's concluding verse shifts from the death formula to a birth formula — Noah's entry does not end with <em>wayyāmōt</em> here (his death is recorded in 9:29). Instead, the genealogy opens outward into the three sons who will populate the post-flood earth. <em>Šēm</em> (name/renown), <em>Ḥām</em> (hot/dark?), <em>Yāpet</em> (enlargement/beauty?) — the three sons whose names head the Table of Nations in ch. 10. The genealogy ends not in death but in the covenant family that will survive judgment.</p>"""
  },
  "6": {
    "1": """<p><strong>wayyĕhî kî-hēḥēl hāʾādām lārōb ʿal-pĕnê hāʾădāmāh</strong>: "When human beings began to increase in number on the face of the ground." <em>Hēḥēl</em> (from <em>ḥālal</em>, H2490, to begin) — the same verb used in 4:26 for the beginning of worship. Here it is the beginning of multiplication — the fulfillment of the creation mandate of 1:28 ("be fruitful and multiply") that now, within a corrupted humanity, produces the conditions for judgment. Multiplication was the blessing; in a fallen world it also multiplies wickedness.</p>""",
    "2": """<p><strong>bĕnê hāʾĕlōhîm</strong>: "Sons of God." This phrase occurs in Job 1:6; 2:1; 38:7 as a term for angelic or divine beings in the heavenly court. Three principal interpretations have been defended: (1) <em>Divine beings</em> (angels/Watchers) — the reading of 1 Enoch, the LXX, and many Church Fathers; supported by the Job parallels; (2) <em>Sethites</em> — the line of Seth (sons of God by covenant), marrying into the Cainite line (daughters of men) — supported by Augustine, Calvin, and others; (3) <em>Dynasts/kings</em> — ancient Near Eastern royal ideology in which kings are called "sons of god"; supported by some ANE comparative evidence. The MKT's "sons of God" preserves the Hebrew without resolving the dispute. <em>Yāpôt</em> (good/beautiful) — the same term used of the six days of creation ("God saw that it was good"); the corruption ironically uses the creator's evaluative vocabulary.</p>""",
    "3": """<p><strong>lōʾ-yādôn rûḥî bāʾādām lĕʿōlām</strong>: "My Spirit will not contend with humans forever." <em>Yādôn</em> is one of the most debated words in the OT; it occurs only here and its root is uncertain. Major options: (1) from <em>dûn</em> (to judge/contend) — "my Spirit will not judge/strive with humanity forever"; (2) from a root meaning "to remain/abide" — "my Spirit will not remain in humanity forever." The LXX reads "remain" (<em>kataménō</em>). The MKT's "contend" follows the majority tradition. <em>Bĕšaggam hûʾ bāśār</em>: "because/for they are flesh" — <em>bāśār</em> (H1320, flesh) here denotes mortal weakness and creatureliness, not sexuality. "120 years" is ambiguous: a deadline for the flood or a new maximum human lifespan. The post-flood genealogy's decreasing lifespans eventually reach 120 (Moses, Deut 34:7), supporting the latter reading.</p>""",
    "4": """<p><strong>hannĕpīlîm</strong>: "The Nephilim." The word <em>nĕpîlîm</em> (H5303) appears only here and in Num 13:33. The root may be <em>nāpal</em> (to fall) — "fallen ones" — or it may be a foreign loanword. The LXX translates as <em>gigantes</em> (giants). The text calls them <em>haggibborîm ʾanšê haššēm</em> — "the mighty men, men of renown" (<em>šēm</em> = name). The phrase <em>ʾanšê haššēm</em> ("men of the name") stands in deliberate contrast to the call to "call upon the name (<em>šēm</em>) of YHWH" in 4:26 — these are men who have made themselves famous rather than calling on God's name. The Nephilim appear "also afterward" — Num 13:33 places them in Canaan; the text leaves their post-flood presence unexplained.</p>""",
    "5": """<p><strong>kol-yēṣer maḥšĕbōt libbô raq raʿ kol-hayyôm</strong>: "Every inclination of the thoughts of his heart was only evil all the day." <em>Yēṣer</em> (H3336, inclination/impulse, from <em>yāṣar</em>, to form/fashion) — the same root as the potter-forming of 2:7. The formed shape of human mental life, its <em>yēṣer</em>, is characterized as <em>raq raʿ kol-hayyôm</em>: only (<em>raq</em>) evil (<em>raʿ</em>) all the day (<em>kol-hayyôm</em>). The three-term intensification allows no exception: the totality of human cognitive inclination, at every moment, tends toward evil. This verse becomes the foundation of the rabbinic concept of the <em>yēṣer hāraʿ</em> (evil inclination) and the Reformed doctrine of total depravity — not that humans do nothing good outwardly, but that the governing orientation of the fallen heart is corrupted at the root.</p>""",
    "6": """<p><strong>wayyinnāḥem YHWH kî-ʿāśāh ʾet-hāʾādām bāʾāreṣ wayyitʿaṣṣēb ʾel-libbô</strong>: "YHWH regretted that he had made humanity on the earth, and his heart was deeply troubled." <em>Nāḥam</em> (H5162, to sigh/regret/comfort) — the same root as Noah's name. Here it denotes genuine divine emotional response to a changed situation, what theologians call anthropopathism (attributing human-like emotions to God for communicative purposes). The verb is not retraction of omniscience; the OT elsewhere affirms God does not repent as humans do (1 Sam 15:29; Num 23:19). The "regret" is the grief of a covenant-making God when his creatures betray the covenant — genuine relational pain, not ignorance about outcomes. <em>Wayyitʿaṣṣēb ʾel-libbô</em> (his heart was pained) — <em>ʿāṣab</em> (H6087) is the same root used of the pain in childbearing (3:16) and the painful labor of the ground (3:17); God's grief over humanity's sin uses the vocabulary of the curse that human sin introduced.</p>""",
    "7": """<p><strong>ʾemḥeh ʾet-hāʾādām ʾăšer-bārāʾtî</strong>: "I will wipe out the humanity that I created." <em>Māḥāh</em> (H4229, to blot out/erase/wipe away) is a strong verb — used of blotting out names (Deut 9:14), blotting out sin (Isa 43:25), and the erasure of Amalek (Deut 25:19). The word choice is extreme: not exile or punishment but annihilation of what was created. The divine speech includes animals, birds, and creatures (<em>šereṣ</em>, crawling things) — the non-human creation suffers because it was made for the sake of humanity and is caught in the consequences of human sin (cf. Rom 8:20-22).</p>""",
    "8": """<p><strong>wĕnōaḥ māṣāʾ ḥēn bĕʿênê YHWH</strong>: "But Noah found favor (<em>ḥēn</em>) in the eyes of YHWH." This is the first occurrence of <em>ḥēn</em> (H2580, grace/favor) in the Bible — 69 occurrences follow in the OT. The word denotes the free, unmerited goodwill of a superior toward an inferior; it is not earned, which is why it is "found" (<em>māṣāʾ</em>) rather than achieved. The NT equivalent <em>charis</em> (grace) derives conceptually from this word. The structural placement of this verse is decisive: v7 ends with God's decision to annihilate; v8 begins with "but Noah" — the exception is pure gift.</p>""",
    "9": """<p><strong>nōaḥ ʾîš ṣaddîq tāmîm hāyāh bĕdōrōtāyw ʾet-hāʾĕlōhîm hithallēk-nōaḥ</strong>: "Noah was a righteous man, blameless among the people of his time; Noah walked with God." Three terms characterize Noah: (1) <em>ṣaddîq</em> (H6662, righteous/just) — the covenant-legal term for one whose conduct conforms to the covenant standard; (2) <em>tāmîm</em> (H8535, blameless/wholesome/complete) — used of sacrificial animals without defect (Lev 1:3) and of Job (Job 1:1); together the two words form the OT gold standard for human righteousness; (3) <em>hithallēk ʾet-hāʾĕlōhîm</em> — the same Hithpael formula as Enoch (5:22,24), denoting continuous walking with God. Heb 11:7 adds the crucial qualifier: "by faith" — Noah's righteousness was covenantally constituted, not self-achieved.</p>""",
    "10": """<p><strong>wayyôled nōaḥ šĕlōšāh bānîm ʾet-šēm ʾet-ḥām wĕʾet-yāpet</strong>: "And Noah fathered three sons: Shem, Ham, and Japheth." The ordering recurs throughout chs. 6-10. <em>Šēm</em> (name/renown) is listed first and will carry the Semitic/covenant lineage. <em>Ḥām</em> (Ham) may mean "hot" or be connected to the Egyptian term for Egypt (<em>Kmt</em>); <em>Yāpet</em> (Japheth) may derive from <em>pāṯāh</em> (to open/enlarge) — cf. 9:27 ("God shall enlarge Japheth"). The three sons are the post-flood prototype of human diversity: one family, three trajectories.</p>""",
    "11": """<p><strong>wattišāḥēt hāʾāreṣ lipnê hāʾĕlōhîm wattimālēʾ hāʾāreṣ ḥāmās</strong>: "The earth was corrupt before God and the earth was full of violence." <em>Šāḥat</em> (H7843, to corrupt/destroy/ruin) appears three times in vv11-12 (corrupt, corrupt, corrupted) — the triple occurrence emphasizes totality. <em>Ḥāmās</em> (H2555, violence) encompasses physical violence, social injustice, and covenant violation; it is the term used of the "witness of violence" in Exod 23:1 and appears throughout the prophets as a charge against corrupt societies (Isa 53:9; Jer 6:7; Mic 6:12; Hab 1:2-3). The combination of <em>šāḥat</em> and <em>ḥāmās</em> defines the pre-flood condition: internal corruption producing outward violence.</p>""",
    "12": """<p><strong>wayyarʾ ʾĕlōhîm ʾet-hāʾāreṣ wĕhinnēh nišḥātāh kî-hišḥît kol-bāśār ʾet-darkô ʿal-hāʾāreṣ</strong>: "God saw the earth, and behold, it was corrupt; for all flesh had corrupted their way on the earth." The divine seeing (<em>rāʾāh</em>) echoes the repeated "God saw that it was good" of ch. 1; here God sees what humanity has made of the good creation. <em>Kol-bāśār</em> (all flesh) — this phrase (used 9 times in the flood narrative) becomes a technical designation for the totality of embodied creaturely life under human dominion. All flesh has <em>hišḥît ʾet-darkô</em> — corrupted its way — humanity has destroyed what it was meant to tend.</p>""",
    "13": """<p><strong>qēṣ kol-bāśār bāʾ lĕpānay</strong>: "The end of all flesh has come before me." <em>Qēṣ</em> (H7093, end/extremity) is the word used in Amos 8:2 ("The end has come upon my people Israel") and Ezek 7:2 ("The end! The end has come"). The flood is announced with the same eschatological vocabulary the prophets will later use for divine judgment on Israel. <em>ʾĂnî mašḥîtām ʾet-hāʾāreṣ</em>: "I am going to destroy them with the earth" — God uses the same root (<em>šāḥat</em>) that described humanity's self-corruption: the destroyer of the earth will be destroyed by the same word that named their offense.</p>""",
    "14": """<p><strong>ʿăśēh lĕkā tēbat ʿăṣê-gōper</strong>: "Make yourself an ark of gopher-wood." <em>Tēbāh</em> (H8392, ark) occurs elsewhere in the OT only in Exod 2:3,5 (Moses's basket) — same word, different scale. Both are rescue-vessels that preserve covenant-bearers through waters of death into a new era. <em>ʿăṣê-gōper</em> (gopher-wood) — the only occurrence of <em>gōper</em> in the OT; the species is unknown, though some equate it with cypress or cedar. <em>Wĕkāpartāh ʾōtāh mibbayt ûmiḥûṣ bakkōper</em>: "coat it inside and out with pitch." <em>Kōper</em> (H3724, pitch/bitumen) shares the consonantal root with <em>kāpar</em> (to cover/atone, H3722) — the same root as <em>kippûr</em> (atonement, Day of Atonement). The bituminous sealing that protects the ark from the waters of judgment uses the same linguistic root as the atoning cover that protects humanity from the wrath of God — a philological connection recognized in rabbinic midrash and many commentators across traditions.</p>""",
    "15": """<p><strong>šĕlōš mēʾôt ʾammāh ōrek hattēbāh ḥămiššîm ʾammāh rāḥbāh ûšĕlōšîm ʾammāh qōmātāh</strong>: "Three hundred cubits long, fifty wide, and thirty high." The cubit (<em>ʾammāh</em>, H520) is approximately 18 inches (45 cm) by the standard cubit, making the ark roughly 450 x 75 x 45 feet (137 x 23 x 14 meters). The proportions (length:width:height = 300:50:30 = 6:1:0.6) match modern naval architecture's stability ratios for seagoing cargo vessels. Ancient Near Eastern parallels (the Gilgamesh Epic's ark is cubical) differ markedly in design; the Genesis ark's elongated proportions are more practically seaworthy.</p>""",
    "16": """<p><strong>ṣōhar taʿăśeh lattēbāh wĕʾel-ʾammāh tĕkallennāh milmāʿlāh</strong>: "Make a roof for it, and finish it to a cubit above." <em>Ṣōhar</em> (H6672) appears only here and its meaning is uncertain: "light-opening," "roof," or "midday light" — the architectural detail may denote a ventilation band around the top of the ark. <em>Petaḥ hattēbāh bĕṣiddāh tāśîm</em>: "Put the door of the ark in its side." A single door and three decks define the only entrance into safety — a structural detail that typologists note alongside John 10:9 ("I am the door") and 14:6 ("I am the way").</p>""",
    "17": """<p><strong>waʾănî hinnĕnî mēbîʾ ʾet-hammabbûl mayim</strong>: "And I, behold, I am bringing the floodwaters." <em>Mabbûl</em> (H3999, flood/deluge) appears 13 times, all in the flood narrative except Ps 29:10 ("YHWH sat enthroned over the flood"); it is a technical term for the primordial waters. <em>WaʾĂnî hinnĕnî</em> (and I, behold) — the divine self-emphasis marks a solemn declaration of intent. <em>Kol-ʾăšer-bô rûaḥ ḥayyîm</em>: "everything in which is the breath of life" — <em>rûaḥ ḥayyîm</em> (breath/spirit of life) echoes 2:7 (God breathed the <em>nišmat ḥayyîm</em>); what God breathed into Adam will be extinguished in all who receive no protection.</p>""",
    "18": """<p><strong>wahăqimōtî ʾet-bĕrîtî ʾittāk</strong>: "But I will establish my covenant with you." The first use of <em>bĕrît</em> (H1285, covenant) in the Bible occurs here, before the formal covenantal elaboration after the flood in ch. 9. <em>Hēqîm bĕrît</em> (to establish/confirm a covenant) is the technical Hiphil formula for activating a previously existing or newly initiated covenant; it implies the covenant has a prior basis (in God's purposes) that is now being formally actualized with Noah. The Noahic covenant is not the first divine-human relationship but the first formally denominated <em>bĕrît</em> — the structural form that will govern all subsequent biblical theology of election and salvation.</p>""",
    "19": """<p><strong>ûmikol-haḥay mikkol-bāśār šĕnayim mikkōl tābîʾ ʾel-hattēbāh</strong>: "And of every living thing, of all flesh, two of every kind you shall bring into the ark." The command uses <em>lĕhaḥăyōt ʾittāk</em> (to keep alive with you) — the purpose of the ark is preservation of life, not just human survival. The taxonomic pairs signal a restoration of the original creative order (Gen 1 establishes the species; the ark preserves the species through judgment). <em>Zākār ûnĕqēbāh</em> (male and female) — the creation binary of 1:27 becomes the survival binary; the reproductive pair is the minimum viable unit for continuation.</p>""",
    "20": """<p><strong>mēhāʿôp lĕmînēhû ûmin-habbĕhēmāh lĕmînāh</strong>: "Of the birds according to their kinds, and of the animals according to their kinds." The <em>lĕmîn</em> (according to kind/species) formula repeats seven times in Gen 1 as the marker of created order; here it recurs as the organizing principle for what will be preserved. The ark is not saving random survivors; it is preserving the created order — the kinds that God made in the beginning — through the judgment that fallen humanity has brought on the creation.</p>""",
    "21": """<p><strong>wĕʾattāh qaḥ-lĕkā mikkol-maʾăkāl ʾăšer yēʾākēl</strong>: "And you, take with you every kind of food that is eaten." The provision of food for the preservation period is a practical divine instruction that underscores the ark's nature: it is not a magical transport but a functional vessel requiring actual preparation and sustaining resources. God commands what Noah must actively do; Noah will do it (v22). The pairing of divine instruction and human obedient action is the pattern of covenant faithfulness throughout Scripture.</p>""",
    "22": """<p><strong>wayyaʿas nōaḥ kĕkōl ʾăšer ṣiwwāh ʾōtô ʾĕlōhîm kēn ʿāśāh</strong>: "Noah did according to all that God commanded him; so he did." The verse is emphatic: <em>kĕkōl ... kēn ʿāśāh</em> (according to all ... so he did). The complete compliance formula echoes Gen 1's "and it was so" — the language of creation is reused for the covenant instruction. What was achieved in creation by divine fiat is achieved in covenant by human obedient response to the divine word. Hebrews 11:7 identifies this as faith: "By faith Noah... in holy fear built an ark."</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    il = json.load(open(str(ROOT / 'data' / 'interlinear' / 'genesis.json')))
    all_ok = True
    for ch in ['4', '5', '6']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(result.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'  ch {ch} MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present.')
    print('Genesis 4-6 mkt-original written.')

if __name__ == '__main__':
    main()
